import React from "react";
import styles from "./table-heading.module.css";
import CartLayout from "../../layout/cart-layout";

const TableHeading = () => {
  return (
    <div className={styles.wrapper_table}>
      <div className="container">
          <CartLayout>
            <h6 className={styles.table_title}>Product</h6>
            <h6 className={`${styles.table_title} ${styles.right_aligned}`}>Price</h6>
            <h6 className={`${styles.table_title} ${styles.right_aligned}`}>Quantity</h6>
            <h6 className={styles.table_title}>Total</h6>
          </CartLayout>
          <div className={styles.divider} />
      </div>
    </div>
  );
};

export default TableHeading;
